var b="url",c="往来记账_1.html",d="generationDate",e=new Date(1781590700564.37),f="defaultAdaptiveView",g="name",h="",i="size",j="width",k=0,l="height",m="adaptiveViews",n="sketchKeys",o="s0",p="variables",q="OnLoadVariable",r="axhubclickvalue",s="page",t="packageId",u="539b20bd9eef44a5bbf0f442f1c96b47",v="type",w="Axure:Page",x="往来记账",y="notes",z="页面概述",A="<p><span style=\"font-family:'Arial Negreta', 'Arial Normal', 'Arial', sans-serif;font-weight:700;color:#D9001B;\">排序</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">：以</span><span style=\"font-family:'Arial Negreta', 'Arial Normal', 'Arial', sans-serif;font-weight:700;color:#333333;\">操作时间</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">顺序进行展示</span></p><p><span style=\"font-family:'Arial Negreta', 'Arial Normal', 'Arial', sans-serif;font-weight:700;color:#D9001B;\">数据来源</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">：3处</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">1.由[财务管理系统&gt;&gt;应收管理：销售结算单]确认的记账</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">&nbsp;&nbsp; &nbsp; a.相关填充字段：客户、</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#3399FF;\">关联单据(XSJZ-)、销售应收</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">、末期应收、已收余额、操作人、操作时间</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">&nbsp;&nbsp; &nbsp; b.其他字段为空，而不是0</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">2.由[财务管理系统&gt;&gt;应收管理：应收款对单调整]确认的记账</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">&nbsp;&nbsp; &nbsp; a.相关填充字段：客户、</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#3399FF;\">关联单据(YSTZ-)、调整追加应收、调整扣除应收</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">、末期应收、已收余额、操作人、操作时间</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">&nbsp;&nbsp; &nbsp; b.其他字段为空，而不是0</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">3.由[财务管理系统&gt;&gt;应收管理：收款单与冲账]确认的记账</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">&nbsp;&nbsp; &nbsp; a.相关填充字段：客户、</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#3399FF;\">关联单据(SK-)、收款金额、余额冲销</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">、末期应收、已收余额、操作人、操作时间</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">&nbsp;&nbsp; &nbsp; b.其他字段为空，而不是0</span></p>",B="annotations",C="fn",D="1",E="ownerId",F="c201ce0661c44ef0bba96a113157a653",G="label",H="关联单据",I="说明",J="<p><span>1.默认提示字“请选择客户”</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; a.展示全部数据</span></p><p><span>2.数据源：[基础数据系统&gt;&gt;客户资料]的客户</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; a.支持对&quot;客户名称&quot;的模糊搜索</span></p><p><span>3.右侧含“×”的快捷清除按钮</span></p><p><span>4.选中/清空：直接返回结果</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; a.针对&quot;客户&quot;列进行检索</span></p>",K="2",L="c717036a1eac44489b36ce5830a7a8b5",M="开始日期  ～  截止日期",N="<p><span>1.默认值</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; a.开始时间：默认空</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; b.截止时间：默认空</span></p><p><span>2.格式：年/月/日</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; a.选中视为'开始日期 00:00:00'至'截止日期 23:59:59'</span></p><p><span>3.快捷筛选</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; a.当月：本月1号~今日</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; b.近1月：上月当日~今日</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; c.近3月：三个月前当日~今日</span></p><p><span>4.开始日期与截止日期选择后</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; a.立即针对“操作时间”列返回筛选结果</span></p>",O="style",P="baseStyle",Q="627587b6038d43cca051c114ac41ad32",R="pageAlignment",S="center",T="fill",U="fillType",V="solid",W="color",X=0xF